/**
 * 用于在 Taro 中接收服务器推送的实时数据流
 *
 * @example
 *
 * ```typescript
 * import { sendChatStream, createChatDataHandler } from '@/utils/chatStream';
 *
 * // 可选 createChatDataHandler 自动解析和累积内容
 * const handleData = createChatDataHandler((content) => {
 *   console.log('累计内容:', content);
 *   setMessage(content);
 * });
 *
 * const { abort } = sendChatStream({
 *   endpoint: '/api/chat',
 *   appId: 'app-xxx',
 *   messages: [{ role: 'user', content: '你好' }],
 *   onUpdate: handleData,
 *   onComplete: () => console.log('对话完成'),
 *   onError: (error) => console.error('错误:', error)
 * });
 *
 * // 手动中止请求
 * abort();
 *
 * ```
 */
import ky, {
    type KyResponse,
    type AfterResponseHook,
    type NormalizedOptions,
} from "ky";
import { createParser, type EventSourceParser } from "eventsource-parser";
import Taro from "@tarojs/taro";

export const EventStreamContentType = "text/event-stream";

const DEFAULT_TIMEOUT = 300000; // 默认超时时长
const SSE_DATA_SEPARATOR = "\\ "; // SSE 数据分隔符

// 判断是否为 H5 环境
function isH5Environment(): boolean {
    try {
        return Taro.getEnv() === Taro.ENV_TYPE.WEB;
    } catch {
        return typeof window !== "undefined" && typeof window.fetch === "function";
    }
}

// 微信小程序环境 手动解析二进制数据
function decodeUtf8(bytes: Uint8Array): string {
    try {
        const charStr = Array.from(bytes, (byte) => String.fromCharCode(byte)).join(
            ""
        );
        return decodeURIComponent(escape(charStr));
    } catch (e) {
        console.warn("UTF-8 decode error:", e);
        return Array.from(bytes, (byte) => String.fromCharCode(byte)).join("");
    }
}

export interface SSEOptions {
    onData: (data: string) => void;
    onEvent?: (event: { id?: string; event?: string; data: string }) => void;
    onCompleted?: (error?: Error) => void;
    onAborted?: () => void;
}

export interface H5SSEOptions extends SSEOptions {
    url: string;
    headers?: Record<string, string>;
    data?: any;
    timeout?: number;
}

// H5 流式请求
export function createH5SSE(options: H5SSEOptions): { abort: () => void } {
    const {
        url,
        headers = {},
        data,
        timeout,
        onData,
        onEvent,
        onCompleted,
        onAborted,
    } = options;

    const controller = new AbortController();

    const createSSEHook =
        (sseOptions: SSEOptions): AfterResponseHook =>
            async (
                request: Request,
                _options: NormalizedOptions,
                response: KyResponse
            ) => {
                if (!response.ok || !response.body) {
                    return;
                }

                let completed = false;
                const innerOnCompleted = (error?: Error): void => {
                    if (completed) return;
                    completed = true;
                    sseOptions.onCompleted?.(error);
                };

                const reader = response.body.getReader();
                const decoder = new TextDecoder("utf8");

                const parser: EventSourceParser = createParser({
                    onEvent: (event) => {
                        if (event.data) {
                            sseOptions.onEvent?.(event);
                            event.data.split(SSE_DATA_SEPARATOR).forEach(sseOptions.onData);
                        }
                    },
                });

                // 读取字节流并解码
                const read = (): void => {
                    reader
                        .read()
                        .then((result: ReadableStreamReadResult<Uint8Array>) => {
                            if (result.done) {
                                innerOnCompleted();
                                return;
                            }

                            parser.feed(decoder.decode(result.value, { stream: true }));
                            read();
                        })
                        .catch((error) => {
                            if (request.signal.aborted) {
                                sseOptions.onAborted?.();
                                return;
                            }
                            innerOnCompleted(error as Error);
                        });
                };

                read();

                return response;
            };

    const sseHook = createSSEHook({ onData, onEvent, onCompleted, onAborted });

    ky.post(url, {
        json: data,
        headers,
        signal: controller.signal,
        timeout,
        hooks: {
            afterResponse: [sseHook],
        },
    }).catch((error) => {
        if (!controller.signal.aborted) {
            onCompleted?.(error as Error);
        }
    });

    return {
        abort: () => controller.abort(),
    };
}

export interface WechatSSEOptions extends SSEOptions {
    url: string;
    headers?: Record<string, string>;
    data?: any;
    timeout?: number;
}

// 微信小程序 流式请求
export function createWechatSSE(options: WechatSSEOptions): {
    abort: () => void;
} {
    const {
        url,
        headers = {},
        data,
        timeout,
        onData,
        onEvent,
        onCompleted,
        onAborted,
    } = options;

    let requestTask: Taro.RequestTask<any> | null = null;
    let completed = false;
    let aborted = false; // 中止标志

    const innerOnCompleted = (error?: Error): void => {
        if (completed) return;
        completed = true;
        onCompleted?.(error);
    };

    try {
        requestTask = Taro.request({
            url,
            method: "POST",
            header: headers,
            data,
            enableChunked: true,
            responseType: "text",
            timeout,
            success: () => !aborted && innerOnCompleted(),
            fail: (err) => {
                if (!aborted) {
                    innerOnCompleted(new Error(err.errMsg || "Request failed"));
                }
            },
        });

        const parser: EventSourceParser = createParser({
            onEvent: (event) => {
                if (aborted || !event.data) return;
                onEvent?.(event);
                event.data.split(SSE_DATA_SEPARATOR).forEach(onData);
            },
        });

        // 分片获取数据
        requestTask.onChunkReceived((res) => {
            if (aborted) return;
            parser.feed(decodeUtf8(new Uint8Array(res.data)));
        });
    } catch (err) {
        innerOnCompleted(err as Error);
    }

    return {
        abort: () => {
            if (requestTask && !aborted) {
                aborted = true;
                try {
                    requestTask.abort();
                    onAborted?.();
                } catch (e) {
                    console.error("Abort request error:", e);
                }
                requestTask = null;
            }
        },
    };
}

// 格式化对话数据
export function createChatDataHandler(
    onUpdate: (content: string) => void
): (data: string) => void {
    let currentContent = "";

    return (data: string): void => {
        try {
            const parsed = JSON.parse(data);
            if (parsed.choices?.[0]?.delta?.content) {
                currentContent += parsed.choices[0].delta.content;
                onUpdate(currentContent);
            }
        } catch {
            console.warn("Failed to parse SSE data:", data);
        }
    };
}

type ContentPart =
    | { type: "text"; text: string }
    | { type: "image_url"; image_url: { url: string } };

export interface ChatMessage {
    role: "user" | "assistant" | "system";
    content: string | ContentPart[];
    id?: string;
}

export interface ChatStreamOptions {
    endpoint: string;
    messages: ChatMessage[];
    appId: string;
    onUpdate: (data: string) => void;
    onComplete?: () => void;
    onError?: (error: Error) => void;
    timeout?: number;
}

// 发送流式请求
export const sendChatStream = (
    options: ChatStreamOptions
): { abort: () => void } => {
    const {
        messages,
        onUpdate,
        onComplete,
        onError,
        timeout = DEFAULT_TIMEOUT,
    } = options;

    const handleCompleted = (error?: Error) =>
        error ? onError?.(error) : onComplete?.();

    const handleAborted = (): void => {
        console.log("Stream aborted");
        onComplete?.();
    };

    const requestData = {
        messages: messages.map((msg) => ({
            role: msg.role,
            content: msg.content,
        })),
        enable_thinking: false,
    };

    const requestHeaders = {
        "X-App-Id": options.appId,
        "Content-Type": "application/json",
    };

    const commonOptions = {
        url: options.endpoint,
        headers: requestHeaders,
        data: requestData,
        timeout,
        onData: onUpdate,
        onCompleted: handleCompleted,
        onAborted: handleAborted,
    };

    const sseInstance = isH5Environment()
        ? createH5SSE(commonOptions) // h5
        : createWechatSSE(commonOptions); // 微信小程序

    return { abort: () => sseInstance.abort() };
};
